import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CourseData {
  course: {
    name: string;
    modulesCompleted: number;
    totalModules: number;
  };
  quizScores: {
    module: string;
    score: number;
  }[];
  timeSpentTrend: number[];
}

export default function Widget() {
  const courseData = response.data as CourseData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#F8FAFC">
              {courseData.course.name}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#94A3B8' }}>
              Modules Completed: {courseData.course.modulesCompleted} / {courseData.course.totalModules}
            </Typography>
            <Stack direction="row" spacing={0.5} sx={{ mt: 1 }}>
              {courseData.quizScores.map((quiz, index) => (
                <Chip
                  key={index}
                  label={`${quiz.module}: ${quiz.score}%`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#3B82F6', color: '#F8FAFC' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: courseData.timeSpentTrend,
                  color: '#F59E0B',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: courseData.timeSpentTrend.map((_, i) => i + 1),
                  scaleType: 'linear',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#6B7280',
                  },
                },
              ]}
              yAxis={[{ tickLabelStyle: { fontSize: 10, fill: '#6B7280' } }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
